-- ==============================================================================
-- SEED TEST DATA FOR YANBA PERFUMES (VALID UUID SCHEMA)
-- ==============================================================================

-- 1. CLEANUP (Optional - Uncomment if you want to clear existing data)
-- TRUNCATE public.inventory, public.product_categories, public.product_tags, public.product_collections, public.products, public.brands, public.categories, public.tags, public.collections RESTART IDENTITY CASCADE;

-- 2. BRANDS (10)
-- Using valid hex IDs: 00000000-0000-0000-0000-000000000001 to 00000000000a
ON CONFLICT (id) DO NOTHING;

-- 3. CATEGORIES (10)
-- 00000000-0000-0000-0000-000000000101 to 00000000010a
ON CONFLICT (id) DO NOTHING;

-- 4. TAGS (10)
-- 00000000-0000-0000-0000-000000000201 to 00000000020a
ON CONFLICT (id) DO NOTHING;

-- 5. COLLECTIONS (10)
-- 00000000-0000-0000-0000-000000000301 to 00000000030a
ON CONFLICT (id) DO NOTHING;

-- 6. PRODUCTS (10)
-- 00000000-0000-0000-0000-000000000401 to 00000000040a
ON CONFLICT (id) DO NOTHING;

-- 7. PRODUCT CATEGORIES (RELATION)
ON CONFLICT (product_id, category_id) DO NOTHING;

-- 8. PRODUCT TAGS (RELATION)
ON CONFLICT (product_id, tag_id) DO NOTHING;

-- 9. PRODUCT COLLECTIONS (RELATION)
ON CONFLICT (product_id, collection_id) DO NOTHING;

-- 10. INVENTORY (quantity_in_grams)
ON CONFLICT (product_id) DO UPDATE SET quantity_in_grams = EXCLUDED.quantity_in_grams;
