INSERT INTO public.brands (id, name, description) VALUES 
('00000000-0000-0000-0000-000000000001', 'أمواج', 'علامة تجارية فاخرة تعكس تراث العطور الشرقية الأصيلة'),
('00000000-0000-0000-0000-000000000002', 'عبد الصمد القرشي', 'سادة العطر الملكي، خبراء العود والعنبر منذ عقود'),
('00000000-0000-0000-0000-000000000003', 'العربية للعود', 'أكبر صانع للعطور الشرقية في العالم'),
('00000000-0000-0000-0000-000000000004', 'الماجد للعود', 'عطور ترتقي بالذوق، مزيج بين الأصالة والحداثة'),
('00000000-0000-0000-0000-000000000005', 'نخبة العود', 'شغف التميز وعطور تناسب كل الأذواق'),
('00000000-0000-0000-0000-000000000006', 'إبراهيم القرشي', 'عراقة الماضي وإبداع الحاضر في عالم العطور'),
('00000000-0000-0000-0000-000000000007', 'الدخيل للعود', 'أصالة العطور الشرقية الممزوجة بأرقى الروائح'),
('00000000-0000-0000-0000-000000000008', 'هند العود', 'عطور تعبر عن الفخامة والأناقة'),
('00000000-0000-0000-0000-000000000009', 'درعة', 'عطور ومنتجات تجميل تلبي احتياجات الأسرة'),
('00000000-0000-0000-0000-00000000000a', 'عساف', 'عطور نادرة بلمسة عربية مميزة')
