INSERT INTO public.products (id, name, description, price_dzd, image_url, brand_id) VALUES 
('00000000-0000-0000-0000-000000000401', 'عطر إنترلود', 'عطر شرقي خشبي يجسد الفوضى والهدوء معاً، بتركيز عالي وثبات خرافي.', 45000, '', '00000000-0000-0000-0000-000000000001'),
('00000000-0000-0000-0000-000000000402', 'سفاري', 'توليفة رائعة من العود القديم مع قطرات من المسك الأبيض الفاخر.', 25000, '', '00000000-0000-0000-0000-000000000002'),
('00000000-0000-0000-0000-000000000403', 'مخلط شمس', 'عطر دافئ ينبض برائحة العود والخشب والتوابل الدافئة.', 15000, '', '00000000-0000-0000-0000-000000000003'),
('00000000-0000-0000-0000-000000000404', 'بلاك ليذر', 'عطر جلدي فخم ذو طابع كلاسيكي جريء للمناسبات الرسمية.', 12000, '', '00000000-0000-0000-0000-000000000004'),
('00000000-0000-0000-0000-000000000405', 'عود أبيض', 'عطر هادئ ومميز يجمع بين العود الأصيل ونعومة الورود البيضاء.', 8000, '', '00000000-0000-0000-0000-000000000005'),
('00000000-0000-0000-0000-000000000406', 'مسك الختام', 'مسك صافي بنكهة زهرية ناعمة يمنحك إحساساً بالنظافة والانتعاش.', 9000, '', '00000000-0000-0000-0000-000000000006'),
('00000000-0000-0000-0000-000000000407', 'كراون الملكي', 'عطر ملكي يجمع بين نفحات العود وزهور الأوركيد الفاخرة.', 18000, '', '00000000-0000-0000-0000-000000000007'),
('00000000-0000-0000-0000-000000000408', 'وردي', 'تركيبة أنثوية جذابة تحتوي على مستخلصات الورد الدمشقي العريق.', 21000, '', '00000000-0000-0000-0000-000000000008'),
('00000000-0000-0000-0000-000000000409', 'ليال', 'عطر مسائي ساحر يغلفك بهالة من الغموض والجاذبية بفضل العنبر والباتشولي.', 5000, '', '00000000-0000-0000-0000-000000000009'),
('00000000-0000-0000-0000-00000000040a', 'مسك الطهارة', 'مسك أبيض نظيف وناعم للاستخدام اليومي لجميع أفراد الأسرة.', 3500, '', '00000000-0000-0000-0000-00000000000a')
